'use client';

import { useState } from 'react';
import Image from 'next/image';
import { AnimatePresence, motion } from 'framer-motion';
import ScrollReveal from '@/components/ScrollReveal';
import Lightbox from '@/components/Lightbox';
import { PORTFOLIO_IMAGES, PORTFOLIO_CATEGORIES } from '@/lib/constants';

export default function PortfolioPage() {
  const [activeCategory, setActiveCategory] = useState<string>('All');
  const [lightboxOpen, setLightboxOpen] = useState(false);
  const [lightboxIndex, setLightboxIndex] = useState(0);

  const filtered =
    activeCategory === 'All'
      ? PORTFOLIO_IMAGES
      : PORTFOLIO_IMAGES.filter((img) => img.category === activeCategory);

  return (
    <>
      {/* Hero */}
      <section className="bg-bg pt-40 pb-16 px-6">
        <div className="max-w-[980px] mx-auto text-center">
          <ScrollReveal>
            <p className="text-gold text-[11px] tracking-[0.2em] uppercase font-medium mb-4">
              Our Work
            </p>
          </ScrollReveal>
          <ScrollReveal delay={0.1}>
            <h1 className="font-serif text-5xl md:text-7xl lg:text-8xl text-text-primary leading-[1.05] mb-5">
              The <span className="italic">Portfolio</span>
            </h1>
          </ScrollReveal>
          <ScrollReveal delay={0.2}>
            <p className="text-text-secondary text-lg max-w-lg mx-auto leading-relaxed">
              A collection of stories told through light, love, and cinematic vision.
            </p>
          </ScrollReveal>
        </div>
      </section>

      {/* Sticky Category Filter Bar */}
      <div className="sticky top-[56px] z-30 bg-bg-white/80 backdrop-blur-xl border-b border-border">
        <div className="max-w-[1400px] mx-auto px-6 py-3 flex flex-wrap justify-center gap-2">
          {PORTFOLIO_CATEGORIES.map((cat) => (
            <button
              key={cat}
              onClick={() => setActiveCategory(cat)}
              className={`px-5 py-2 text-sm tracking-wide rounded-full transition-all duration-300 ${
                activeCategory === cat
                  ? 'bg-text-primary text-white font-medium'
                  : 'text-text-secondary hover:text-text-primary'
              }`}
            >
              {cat}
            </button>
          ))}
        </div>
      </div>

      {/* Gallery */}
      <section className="py-16 md:py-24 px-6 bg-bg">
        <div className="max-w-[1400px] mx-auto">
          <AnimatePresence mode="wait">
            <motion.div
              key={activeCategory}
              initial={{ opacity: 0, y: 12 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -8 }}
              transition={{ duration: 0.35 }}
              className="columns-1 sm:columns-2 lg:columns-3 gap-5 space-y-5"
            >
              {filtered.map((img, i) => (
                <ScrollReveal key={`${activeCategory}-${i}`} delay={i * 0.04}>
                  <div
                    className="relative overflow-hidden rounded-xl cursor-pointer break-inside-avoid group transition-all duration-500 hover:shadow-lg hover:scale-[1.02]"
                    onClick={() => {
                      setLightboxIndex(i);
                      setLightboxOpen(true);
                    }}
                  >
                    <Image
                      src={img.src}
                      alt={img.alt}
                      width={img.width}
                      height={img.height}
                      className="w-full h-auto object-cover"
                      loading="lazy"
                    />
                    {/* Hover overlay */}
                    <div className="absolute inset-0 bg-black/0 group-hover:bg-black/30 transition-colors duration-500" />
                    <div className="absolute bottom-0 left-0 right-0 p-4 opacity-0 group-hover:opacity-100 translate-y-2 group-hover:translate-y-0 transition-all duration-500">
                      <span className="text-[10px] text-gold tracking-[0.2em] uppercase font-medium">
                        {img.category}
                      </span>
                      <p className="text-white text-sm mt-0.5">{img.alt}</p>
                    </div>
                  </div>
                </ScrollReveal>
              ))}
            </motion.div>
          </AnimatePresence>
        </div>
      </section>

      <Lightbox
        images={filtered}
        initialIndex={lightboxIndex}
        isOpen={lightboxOpen}
        onClose={() => setLightboxOpen(false)}
      />
    </>
  );
}
